using System.Collections.ObjectModel;using System.ComponentModel;using System.Runtime.CompilerServices;using System.Windows;using Exam.Core;using Exam.Data;namespace Exam.App;public partial class MainWindow:Window,INotifyPropertyChanged{readonly MaterialRepository repo=new();List<Material> all=new();int page=1;public ObservableCollection<Material> PageItems{get;}=new();public List<string> Types{get;set;}=new();public string[] Sorts{get;}={"Title","Stock","Cost"};string search="";public string Search{get=>search;set{search=value;page=1;Refresh();}}string selectedType="All types";public string SelectedType{get=>selectedType;set{selectedType=value;page=1;Refresh();}}string selectedSort="Title";public string SelectedSort{get=>selectedSort;set{selectedSort=value;Refresh();}}public Material? Selected{get;set;}public double MassValue{get;set;}public string Counter{get;set;}="";public RelayCommand AddCommand{get;}public RelayCommand EditCommand{get;}public RelayCommand DeleteCommand{get;}public RelayCommand MassCommand{get;}public RelayCommand NextCommand{get;}public RelayCommand PrevCommand{get;}public MainWindow(){InitializeComponent();DataContext=this;all=repo.Load();Types=all.Select(x=>x.Type).Distinct().Prepend("All types").ToList();AddCommand=new(_=>{all.Add(new Material{Id=all.Count+1,Title="New material",Type=Types.Skip(1).FirstOrDefault()??"Type",Cost=1,MinCount=1,CountInPack=1});Save();});EditCommand=new(_=>{if(Selected!=null){Selected.Title+=" *";Save();}});DeleteCommand=new(_=>{if(Selected==null)return;if(!repo.CanDelete(Selected)){MessageBox.Show("Deletion is blocked: product material exists.");return;}all.Remove(Selected);Save();});MassCommand=new(_=>{if(Selected!=null)Selected.MinCount=MassValue;Save();});NextCommand=new(_=>{page++;Refresh();});PrevCommand=new(_=>{if(page>1)page--;Refresh();});Refresh();}void Save(){repo.Save(all);Refresh();}void Refresh(){IEnumerable<Material> q=all;if(!string.IsNullOrWhiteSpace(Search))q=q.Where(x=>(x.Title+x.Description).Contains(Search,StringComparison.OrdinalIgnoreCase));if(SelectedType!="All types")q=q.Where(x=>x.Type==SelectedType);q=SelectedSort switch{"Stock"=>q.OrderBy(x=>x.CountInStock),"Cost"=>q.OrderBy(x=>x.Cost),_=>q.OrderBy(x=>x.Title)};var list=q.ToList();PageItems.Clear();foreach(var i in ListTools.Page(list,page,15))PageItems.Add(i);Counter=$"shown {PageItems.Count} of {list.Count}";OnPropertyChanged(nameof(Counter));}public event PropertyChangedEventHandler? PropertyChanged;void OnPropertyChanged([CallerMemberName]string? n=null)=>PropertyChanged?.Invoke(this,new PropertyChangedEventArgs(n));}
